class Solution(object):
    def smallestNumber(self, pattern):
        n = len(pattern)
        result = list(range(1, n + 2))
        i = 0
        while i < n:
            if pattern[i] == 'D':
                j = i
                while j < n and pattern[j] == 'D':
                    j += 1
                result[i:j+1] = reversed(result[i:j+1])
                i = j + 1
            else:
                i += 1
        return ''.join(map(str, result))
